def save_session(self, filepath: str) -> Dict[str, Any]:
    """将当前会话保存到 JSON 文件。

    使用 write-to-temp-then-rename 原子写入模式，防止崩溃时丢失已有会话文件。

    Args:
        filepath: 保存路径

    Returns:
        {"success": True, "path": filepath} 或 {"success": False, "error": ...}
    """
    import tempfile
    try:
        dir_name = os.path.dirname(filepath) or "."
        os.makedirs(dir_name, exist_ok=True)
        data = self.export_session()
        # 原子写入：先写临时文件，再 rename 替换目标
        fd, tmp_path = tempfile.mkstemp(dir=dir_name, suffix=".tmp")
        try:
            with os.fdopen(fd, "w", encoding="utf-8") as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
            os.replace(tmp_path, filepath)
        except BaseException:
            # 写入或 rename 失败时清理临时文件
            try:
                os.unlink(tmp_path)
            except OSError:
                pass
            raise
        return {"success": True, "path": filepath}
    except Exception as e:
        return {"success": False, "error": str(e)}

def save_archival(self) -> bool:
    """将长期记忆持久化到文件。

    使用 write-to-temp-then-rename 原子写入模式，防止崩溃时丢失已有长期记忆。

    Returns:
        是否成功保存
    """
    import tempfile
    try:
        os.makedirs(self._archival_dir, exist_ok=True)
        # 原子写入：先写临时文件，再 rename 替换目标
        fd, tmp_path = tempfile.mkstemp(dir=self._archival_dir, suffix=".tmp")
        try:
            with os.fdopen(fd, 'w', encoding='utf-8') as f:
                for entry in self.archival[-self.MAX_ARCHIVAL_ENTRIES:]:
                    json.dump({
                        "content": entry.content,
                        "timestamp": entry.timestamp,
                        "source": entry.source,
                    }, f, ensure_ascii=False)
                    f.write("\n")
            os.replace(tmp_path, self._archival_path)
        except BaseException:
            try:
                os.unlink(tmp_path)
            except OSError:
                pass
            raise
        return True
    except Exception:
        return False

